INSERT IGNORE INTO gear_items (id, owner_id, title, category_id, `condition`, brand, suitable_age, description, photos, status, price_type, price, created_at) VALUES
(1, 1, '好孩子轻便伞车九成新', 1, '九成新', '好孩子', '6个月-3岁', '自用轻便伞车一辆，可单手收车，出门携带方便。宝宝已上幼儿园，不再使用，车况良好，轮子顺滑。', NULL, 'Available', '议价', NULL, '2025-02-15 10:00:00'),
(2, 2, '宜家安东伯格儿童餐椅', 2, '九成新', '宜家', '6个月-3岁', '经典宜家儿童餐椅，白色款，带托盘。易清洁，非常实用。宝宝长大了换了大椅子，小椅子闲置中。', NULL, 'Reserved', '免费', NULL, '2025-02-20 11:30:00'),
(3, 3, '全棉时代新生儿连体衣套装', 3, '全新', '全棉时代', '0-3个月', '朋友送的全新连体衣套装（3件），纯棉材质，标签都还在。我家宝宝出生时穿不上，一直放着没动过。', NULL, 'Available', '固定价', 59.00, '2025-03-01 09:00:00'),
(4, 1, '费雪益智积木套装', 4, '七成新', '费雪', '1岁-3岁', '费雪大颗粒积木，适合小宝宝抓握。部分贴纸有磨损，不影响使用，可以锻炼宝宝动手能力。', NULL, 'HandedOver', '免费', NULL, '2025-03-05 14:00:00'),
(5, 4, '可优比实木婴儿床', 5, '九成新', '可优比', '0-2岁', '实木婴儿床，可调节床板高度，侧栏可放下与大床拼接。使用了一年多，无漆款很安全。', NULL, 'Available', '议价', NULL, '2025-03-10 16:00:00'),
(6, 5, '宝得适双面骑士安全座椅', 6, '九成新', '宝得适', '0-4岁', '正反双向安装安全座椅，isofix接口。宝宝换了大童座椅，这个闲置了。无事故记录，安全可靠。', NULL, 'Available', '固定价', 680.00, '2025-03-15 10:30:00'),
(7, 3, '木玩世家早教绕珠', 4, '七成新', '木玩世家', '1岁-3岁', '实木绕珠玩具，色彩鲜艳，锻炼宝宝手眼协调。有些磨损痕迹，功能完好。', NULL, 'Archived', '免费', NULL, '2025-03-20 13:00:00'),
(8, 2, 'NUK婴儿睡袋四季款', 5, '全新', 'NUK', '0-6个月', '全新NUK四季睡袋，薄款适合空调房，双向拉链方便换尿布。买多了用不上，全新未拆封。', NULL, 'Available', '固定价', 88.00, '2025-04-01 08:30:00');
