(2, 2, 2, 4, '2025-04-05 14:00:00', '海淀区五道口华联商场门口', 'Pending', '约好了这周六交接，希望天气好'),
(3, 7, 3, 5, '2025-04-10 16:00:00', '西城区金融街购物中心', 'Cancelled', '接收方临时有事无法前来，已取消'),
(4, 6, 5, 1, '2025-04-15 11:00:00', '东城区东直门来福士广场', 'Pending', '安全座椅比较重，需要开车来自提');
INSERT IGNORE INTO gear_stories (id, gear_item_id, user_id, content, photos, created_at) VALUES
(1, 4, 3, '收到张伟转让的费雪积木，宝宝特别喜欢！每天都要玩一会儿，现在已经能自己搭小塔了。感谢这个平台让闲置物品传递温暖！', NULL, '2025-03-22 09:00:00'),
(2, 4, 1, '看着自己宝宝用过的积木在另一个小朋友手中继续发挥作用，心里特别温暖。希望更多家长能加入进来，让好东西不浪费。', NULL, '2025-03-22 10:30:00'),
(3, 2, 2, '这款宜家餐椅真的太实用了，从宝宝6个月坐稳开始用到现在，清洗方便，结实耐用。希望下一个家庭也能喜欢它！', NULL, '2025-03-25 15:00:00'),
(4, 6, 5, '宝得适安全座椅陪伴了宝宝三年，安全又放心。每次开车出门都很有安全感。因为宝宝长大需要换座椅了，希望下一个小宝贝也能被好好保护。', NULL, '2025-04-02 11:00:00'),
(5, 3, 3, '朋友送的全棉时代连体衣质量真的很好，纯棉柔软舒适。可惜我家宝宝出生就偏大，0-3个月的尺码穿不上。希望有需要的家庭能用到，别浪费了这么好的衣服。', NULL, '2025-04-05 14:30:00');
INSERT IGNORE INTO wishlists (id, user_id, title, category_id, expected_condition, city, acceptable_wear_level, description, status, matched_gear_item_id, created_at, updated_at) VALUES
(1, 2, '求购九成新婴儿推车', 1, '九成新', '北京', '轻微使用痕迹', '宝宝马上6个月了，需要一辆轻便的婴儿推车，最好是大品牌，安全性要有保障。预算有限，希望能遇到合适的。', 'Open', NULL, '2025-04-10 09:00:00', '2025-04-10 09:00:00'),
(2, 3, '求购新生儿安全座椅', 6, '九成新', '上海', '无明显划痕', '预产期在6月，急需一台0-4岁可用的安全座椅，希望是isofix接口的，无事故记录。', 'Open', NULL, '2025-04-12 14:30:00', '2025-04-12 14:30:00'),
(3, 4, '求购婴儿实木床', 5, '八成新', '北京', '可接受小磕碰', '宝宝下个月就要出生了，想要一张实木婴儿床，最好能和大床拼接，价格好商量。', 'Fulfilled', 5, '2025-04-08 10:15:00', '2025-04-15 11:00:00'),
(4, 5, '求购1-3岁益智玩具', 4, '七成新', '广州', '可接受磨损', '宝宝刚满1岁，想找一些适合这个年龄段的益智玩具，只要功能完好就行，外观新旧不太介意。', 'Open', NULL, '2025-04-18 16:45:00', '2025-04-18 16:45:00'),
(5, 1, '求购6-12个月婴儿衣物', 3, '全新', '深圳', '全新未拆封', '宝宝长得太快，衣服很快就穿不下了。想找一些全新或者几乎全新的6-12个月宝宝衣服，最好是纯棉材质的。', 'Open', NULL, '2025-04-20 08:30:00', '2025-04-20 08:30:00');
